fixed_code:
fn main() {
    let mut vec = vec![1, 2, 3];
    let idx: usize = 5;
    if idx < vec.len() {
        println!("Value at index {}: {}", idx, vec[idx]);
    } else {
        println!("Index out of bounds");
    }
}
